changeSet.sql:
ALTER TYPE QuestionType RENAME TO QuestionType__;
CREATE TYPE QuestionType AS ENUM ('Organization', 'System', 'Vendor', 'Cloud', 'Both', 'GDPRSystem', 'GDPROrganization');

ALTER TABLE qualitative_questions
	ALTER COLUMN vendor_type DROP DEFAULT,
	ALTER COLUMN vendor_type type QuestionType using vendor_type::text::QuestionType,
	ALTER COLUMN vendor_type SET DEFAULT 'Organization';

update qualitative_questions set vendor_type = 'System' where vendor_type = 'Organization';

DROP TYPE QuestionType__;
